UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('b469ee53-5991-45c0-ac47-61f164f08683'::uuid, 'Les aminosides fragilisent la flore intestinale, les probiotiques Lactibiane aident à restaurer son équilibre.'),('6ef79950-16e3-460f-930e-98e0707344be'::uuid, 'Les aminosides peuvent affaiblir le système immunitaire, la vitamine C 500mg soutient les défenses naturelles de l''organisme.'),('5373b94d-ee49-4212-bb16-151e6f5c29ee'::uuid, 'Les traitements peuvent irriter la gorge, le spray propolis apaise localement les muqueuses inflammées.'),('fbb890a9-5720-43ae-8158-35cca89ed802'::uuid, 'Les analogues GLP-1 influencent la glycémie, un lecteur permet de surveiller précisément les niveaux de sucre pour un meilleur contrôle.'),('0fb3ecf1-8663-4881-a62a-35254df90e53'::uuid, 'Les analogues GLP-1 gèrent le métabolisme glucidique, le chrome et la cannelle soutiennent l''équilibre de la glycémie.'),('ee04f5d9-b74e-4b49-8e1e-536928934fc9'::uuid, 'Le diabète peut fragiliser la peau des pieds, une crème spécifique aide à maintenir l''hydratation et prévenir les lésions.'),('510c0733-7991-44b8-8865-d86e3acbe5fb'::uuid, 'Certains traitements peuvent influencer l''immunité, la vitamine D3 soutient la fonction immunitaire et la santé osseuse.'),('f8b87ed5-c5c6-4315-bdaf-6082a37279a0'::uuid, 'Les anesthésiques locaux peuvent induire une certaine fatigue, le magnésium B6 aide à la récupération neuromusculaire et réduit le stress.'),('9b10be7a-b3a5-4d16-ba42-ffa126ffe1b3'::uuid, 'Les anti-androgènes peuvent affecter la densité osseuse, la vitamine D3 est essentielle pour son maintien.'),('b6b43dd7-4649-4b34-8dd7-ef1d14266f0c'::uuid, 'Les traitements peuvent altérer le métabolisme osseux, le calcium et le magnésium soutiennent la structure du squelette.'),('a429df1c-28eb-4210-a8a0-bb07fa4f3535'::uuid, 'Certains traitements peuvent influencer le système endocrinien, le sélénium et le zinc agissent comme antioxydants cellulaires.'),('19d37db9-5379-4c1c-8791-fbdc05bc314c'::uuid, 'Les anti-œstrogènes peuvent avoir un impact sur la densité osseuse, la vitamine D3 contribue au maintien des os solides.'),('411b50bf-2d8d-4779-8e85-5c0c648b64e2'::uuid, 'Les traitements peuvent influencer la santé osseuse, le calcium et le magnésium sont essentiels à la solidité du squelette.'),('5700579d-0dc1-4332-80dc-ac8a90ba42e2'::uuid, 'Les traitements peuvent perturber l''équilibre thyroïdien, le sélénium et le zinc agissent comme antioxydants protecteurs.'),('5c759090-f713-4f45-b83b-422baedfa70b'::uuid, 'Les anti-H2 peuvent modifier l''acidité gastrique, les probiotiques aident à maintenir l''équilibre de la flore digestive.'),('c8fb5914-bb71-4e54-af3a-8ef0cf6e580a'::uuid, 'Les anti-H2 peuvent occasionner des désagréments digestifs, le Smecta protège la muqueuse intestinale en cas d''irritation.'),('3ee121a0-38ae-416c-9a2c-b5f139219bf4'::uuid, 'Les anti-H2 peuvent altérer la digestion, une tisane digestive aide à atténuer les ballonnements et spasmes intestinaux.'),('af46be61-66e1-4d17-9e50-22eb27b72763'::uuid, 'Les anti-infectieux peuvent déséquilibrer la flore intestinale, les probiotiques Lactibiane aident à restaurer sa composition.'),('4fe7c16b-b0ea-4dd7-86fa-71dacc7275c6'::uuid, 'Les anti-infectieux peuvent affaiblir l''immunité générale, la vitamine C 500mg soutient les défenses naturelles de l''organisme.'),('d26cb6b3-527a-4a80-82d4-033247808715'::uuid, 'Les traitements peuvent irriter la gorge, le spray propolis apaise localement les muqueuses enflammées et douloureuses.'),('d7936865-8578-4287-93f9-2f678f856061'::uuid, 'Les anti-infectieux ophtalmiques peuvent impacter l''équilibre digestif, les probiotiques Lactibiane aident à préserver la flore intestinale.'),('d2776c02-c306-44e8-bc25-4a63254b435e'::uuid, 'Les infections oculaires sollicitent l''immunité, la vitamine C renforce les défenses naturelles pour une meilleure récupération.'),('4860771f-2442-4835-9ad9-f94856aa274a'::uuid, 'Les irritations de la gorge peuvent accompagner une infection, la propolis forme une barrière protectrice et apaise la muqueuse.'),('03d4fcfd-bdc7-4ffe-8b38-f4443ff7c149'::uuid, 'Les douleurs musculaires entraînent une inflammation locale, le gel d''arnica aide à la réduire grâce à son action anti-inflammatoire naturelle.'),('f28ec96d-1c48-4ff7-a8d7-35d7db9bed75'::uuid, 'Les tensions musculaires sont souvent liées à un déséquilibre électrolytique, le magnésium et la B6 favorisent une bonne fonction musculaire.'),('5fee65eb-c7d7-4841-aa75-3c1a1f1f8f36'::uuid, 'Les contractures musculaires créent des zones de tension, la chaleur locale relâche les fibres musculaires pour une détente.'),('a3c57533-a901-44bd-991c-cf121562f6c3'::uuid, 'Certains traitements compromettent la densité osseuse et l''immunité, la vitamine D3 optimise l''absorption du calcium et soutient les défenses immunitaires.'),('970cdd4c-2c74-4369-a6ad-fca12163e3c4'::uuid, 'Le stress peut épuiser les réserves de magnésium, le magnésium marin et la B6 réduisent la fatigue nerveuse et musculaire.'),('d89cb012-0624-4298-8eb1-d59365623ac5'::uuid, 'Un traitement lourd peut perturber la flore intestinale, les probiotiques rétablissent l''équilibre digestif et immunitaire.'),('6ba30a0c-db94-4a9a-8c45-e81928642dc5'::uuid, 'La congestion nasale est due à une hyperproduction de mucus, l''eau de mer hypertonique aide à désencombrer le nez par osmose.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;